/*
  script.js (updated)
  - Paste your front/back Base64 images into FRONT_IMAGE_BASE64 / BACK_IMAGE_BASE64.
  - Uses detailed normalized polygons tailored to your images (uploaded).
  - Centers & scales images correctly; provides debug overlay.
*/

/* ========== USER: insert your base64 images here ========== */
const FRONT_IMAGE_BASE64 = "data:image/jpeg;base64,"; // example: "data:image/png;base64,..."
const BACK_IMAGE_BASE64  = "data:image/jpeg;base64,";

/* ========== Config ========== */
const DEGREE_COLORS = {
  1: { cssClass: "degree-1", rgba: "rgba(255,215,215,0.95)" },
  2: { cssClass: "degree-2", rgba: "rgba(255,138,107,0.95)" },
  3: { cssClass: "degree-3", rgba: "rgba(160,0,0,0.95)" }
};

/* ========== Detailed normalized polygons (front + back).
   Coordinates normalized to [0,1] where (0,0)=top-left canvas, (1,1)=bottom-right.
   These were created to match your uploaded images (sizes ~271x600, 269x600).
   If you replace images, keep polygons in sync.
*/
const REGIONS = [
  // FRONT (use same polygon shape for front/back variants but will be labeled)
  // Head (front)
  { id:"head_front", name:"Head (front)", percentage:4.5, poly:[
    [0.395,0.02],[0.605,0.02],[0.675,0.095],[0.605,0.155],[0.395,0.155],[0.325,0.095]
  ]},
  // Head back
  { id:"head_back", name:"Head (back)", percentage:4.5, poly:[
    [0.395,0.02],[0.605,0.02],[0.675,0.095],[0.605,0.155],[0.395,0.155],[0.325,0.095]
  ]},

  // Left Arm (front)
  { id:"left_arm_front", name:"Left Arm (front)", percentage:4.5, poly:[
    [0.08,0.17],[0.17,0.17],[0.24,0.30],[0.21,0.43],[0.14,0.48],[0.09,0.35]
  ]},
  // Left Arm (back)
  { id:"left_arm_back", name:"Left Arm (back)", percentage:4.5, poly:[
    [0.08,0.17],[0.17,0.17],[0.24,0.30],[0.21,0.43],[0.14,0.48],[0.09,0.35]
  ]},

  // Right Arm (front)
  { id:"right_arm_front", name:"Right Arm (front)", percentage:4.5, poly:[
    [0.92,0.17],[0.83,0.17],[0.76,0.30],[0.79,0.43],[0.86,0.48],[0.91,0.35]
  ]},
  // Right Arm (back)
  { id:"right_arm_back", name:"Right Arm (back)", percentage:4.5, poly:[
    [0.92,0.17],[0.83,0.17],[0.76,0.30],[0.79,0.43],[0.86,0.48],[0.91,0.35]
  ]},

  // Anterior trunk (chest + abdomen)
  { id:"anterior_trunk", name:"Anterior Trunk", percentage:18, poly:[
    [0.395,0.155],[0.605,0.155],[0.71,0.355],[0.62,0.63],[0.38,0.63],[0.29,0.355]
  ]},
  // Posterior trunk
  { id:"posterior_trunk", name:"Posterior Trunk", percentage:18, poly:[
    [0.395,0.155],[0.605,0.155],[0.71,0.355],[0.62,0.63],[0.38,0.63],[0.29,0.355]
  ]},

  // Left Leg (front)
  { id:"left_leg_front", name:"Left Leg (front)", percentage:9, poly:[
    [0.395,0.63],[0.47,0.63],[0.49,0.92],[0.47,0.99],[0.395,0.99],[0.36,0.92]
  ]},
  // Left Leg (back)
  { id:"left_leg_back", name:"Left Leg (back)", percentage:9, poly:[
    [0.395,0.63],[0.47,0.63],[0.49,0.92],[0.47,0.99],[0.395,0.99],[0.36,0.92]
  ]},

  // Right Leg (front)
  { id:"right_leg_front", name:"Right Leg (front)", percentage:9, poly:[
    [0.605,0.63],[0.53,0.63],[0.51,0.92],[0.53,0.99],[0.605,0.99],[0.64,0.92]
  ]},
  // Right Leg (back)
  { id:"right_leg_back", name:"Right Leg (back)", percentage:9, poly:[
    [0.605,0.63],[0.53,0.63],[0.51,0.92],[0.53,0.99],[0.605,0.99],[0.64,0.92]
  ]},

  // Perineum (small central)
  { id:"perineum", name:"Perineum", percentage:1, poly:[
    [0.485,0.835],[0.515,0.835],[0.515,0.895],[0.485,0.895]
  ]}
];

/* ====== UI wiring ====== */
const mainCanvas = document.getElementById('mainCanvas');
const ctx = mainCanvas.getContext('2d');

let canvasWidth = mainCanvas.width;
let canvasHeight = mainCanvas.height;

/* Offscreen mask canvas (where strokes are actually painted) */
const maskCanvases = {
  front: document.createElement('canvas'),
  back: document.createElement('canvas')
};
const maskContexts = {
  front: maskCanvases.front.getContext('2d'),
  back: maskCanvases.back.getContext('2d')
};
maskCanvases.front.width = canvasWidth;
maskCanvases.front.height = canvasHeight;
maskCanvases.back.width = canvasWidth;
maskCanvases.back.height = canvasHeight;

/* Keep strokes for undo */
let strokesByView = { front: [], back: [] }; // stroke: { points: [...], size, degree, color, view }
let isDrawing = false;
let currentStroke = null;
let view = 'front'; // or back
let debugOverlay = false;

let imgFront = new Image();
let imgBack = new Image();
let frontLoaded = false, backLoaded = false;

/* UI elements */
const toggleViewBtn = document.getElementById('toggleViewBtn');
const debugToggleBtn = document.getElementById('debugToggleBtn');
const degreeSelect = document.getElementById('degreeSelect');
const brushSizeInput = document.getElementById('brushSize');
const undoBtn = document.getElementById('undoBtn');
const clearBtn = document.getElementById('clearBtn');
const totalTBSAEl = document.getElementById('totalTBSA');
const degreeBreakdownEl = document.getElementById('degreeBreakdown');
const regionsAffectedEl = document.getElementById('regionsAffected');
const syncStatusEl = document.getElementById('syncStatus');
const saveBtn = document.getElementById('saveBtn');
const serverCalcBtn = document.getElementById('serverCalcBtn');
const urlParams = new URLSearchParams(window.location.search);
const activePatientId = urlParams.get('patientId');
const returnUrl = urlParams.get('returnUrl') || 'http://localhost:3000/#/patients';

function buildReturnUrlWithTbsa(baseUrl, tbsa){
  const encodedTbsa = encodeURIComponent(String(Number(tbsa).toFixed(2)));

  if (baseUrl.includes('#')) {
    const [prefix, hashPart = ''] = baseUrl.split('#');
    const joiner = hashPart.includes('?') ? '&' : '?';
    return `${prefix}#${hashPart}${joiner}tbsa=${encodedTbsa}`;
  }

  const joiner = baseUrl.includes('?') ? '&' : '?';
  return `${baseUrl}${joiner}tbsa=${encodedTbsa}`;
}

if (syncStatusEl && activePatientId) {
  syncStatusEl.textContent = `Linked patient: ${activePatientId}`;
}

/* Load provided base64 or leave blank (blank = empty background) */
if (FRONT_IMAGE_BASE64) {
  imgFront.src = FRONT_IMAGE_BASE64;
  imgFront.onload = () => { frontLoaded = true; drawAll(); };
}
if (BACK_IMAGE_BASE64) {
  imgBack.src = BACK_IMAGE_BASE64;
  imgBack.onload = () => { backLoaded = true; drawAll(); };
}

/* Helper: fit image into canvas with preserved aspect + centered */
function computeImagePlacement(img, canvasW, canvasH){
  if (!img || !img.naturalWidth) return { x:0,y:0,w:canvasW,h:canvasH, scale: canvasW/img.width };
  const iw = img.naturalWidth, ih = img.naturalHeight;
  const scale = Math.min(canvasW / iw, canvasH / ih);
  const w = iw * scale, h = ih * scale;
  const x = (canvasW - w) / 2;
  const y = (canvasH - h) / 2;
  return { x, y, w, h, scale };
}

/* Map normalized poly -> pixel coordinates using current image placement
   We map normalized coordinates relative to the drawn image rectangle (not whole canvas) so polygons align to body,
   accounting for white margins in source PNGs.
*/
function polyToPixels(poly, targetView = view){
  const img = (targetView==='front' ? imgFront : imgBack);
  const placement = computeImagePlacement(img, canvasWidth, canvasHeight);
  const { x:ox, y:oy, w:iw, h:ih } = placement;
  return poly.map(([nx,ny]) => {
    return [ Math.round(ox + nx * iw), Math.round(oy + ny * ih) ];
  });
}

/* Create region mask imageData */
function createRegionMask(region, targetView = view){
  const tmp = document.createElement('canvas');
  tmp.width = canvasWidth; tmp.height = canvasHeight;
  const tctx = tmp.getContext('2d');
  tctx.fillStyle = 'white';
  tctx.beginPath();
  const pix = polyToPixels(region.poly, targetView);
  tctx.moveTo(pix[0][0], pix[0][1]);
  for (let i=1;i<pix.length;i++) tctx.lineTo(pix[i][0], pix[i][1]);
  tctx.closePath();
  tctx.fill();
  return tctx.getImageData(0,0,canvasWidth,canvasHeight);
}

/* Count non-transparent pixels in ImageData */
function countNonTransparent(data){
  let c=0;
  for (let i=0;i<data.data.length;i+=4){
    if (data.data[i+3]>20) c++;
  }
  return c;
}

function roundToTwo(value){
  return Math.round((Number(value) + Number.EPSILON) * 100) / 100;
}

function getRegionsForView(targetView){
  return REGIONS.filter(region => {
    if (targetView === 'front') {
      return region.id.endsWith('_front') || region.id === 'anterior_trunk' || region.id === 'perineum';
    }
    return region.id.endsWith('_back') || region.id === 'posterior_trunk';
  });
}

function computeTBSAForView(targetView){
  const maskData = maskContexts[targetView].getImageData(0,0,canvasWidth,canvasHeight);
  let totalTBSA = 0;
  const breakdown = {1:0,2:0,3:0};
  const regionsAffected = [];
  for (const region of getRegionsForView(targetView)){
    const regionImg = createRegionMask(region, targetView);
    const rdata = regionImg.data;
    let regionPixelCount = 0;
    let markedCounts = {1:0,2:0,3:0};
    for (let i=0;i<rdata.length;i+=4){
      if (rdata[i+3]>10){
        regionPixelCount++;
        const r = maskData.data[i], g = maskData.data[i+1], b = maskData.data[i+2], a = maskData.data[i+3];
        if (a>20){
          // match degree by color heuristics (consistent with painting colors)
          if (r>230 && g>200) markedCounts[1]++;
          else if (r>240 && g>100 && b>80) markedCounts[2]++;
          else if (r>140 && g<50 && b<50) markedCounts[3]++;
          else markedCounts[2]++;
        }
      }
    }
    if (regionPixelCount===0) continue;
    const markedTotal = markedCounts[1]+markedCounts[2]+markedCounts[3];
    const regionMarked = markedTotal;
    const frac = regionMarked / regionPixelCount;
    const contrib = frac * region.percentage;
    if (contrib>0){
      regionsAffected.push({ id: region.id, name: region.name, percent: roundToTwo(contrib) });
      totalTBSA += contrib;
      if (markedTotal>0){
        breakdown[1] += (markedCounts[1]/markedTotal) * contrib;
        breakdown[2] += (markedCounts[2]/markedTotal) * contrib;
        breakdown[3] += (markedCounts[3]/markedTotal) * contrib;
      }
    }
  }
  totalTBSA = roundToTwo(Math.min(100, totalTBSA));
  return {
    totalTBSA,
    breakdown: {
      1: roundToTwo(breakdown[1]),
      2: roundToTwo(breakdown[2]),
      3: roundToTwo(breakdown[3])
    },
    regionsAffected
  };
}

/* Compute TBSA locally using separate front/back masks and sum both sides */
function computeLocalTBSA(){
  const front = computeTBSAForView('front');
  const back = computeTBSAForView('back');

  const totalTBSA = roundToTwo(Math.min(100, front.totalTBSA + back.totalTBSA));
  const breakdown = {
    1: roundToTwo(front.breakdown[1] + back.breakdown[1]),
    2: roundToTwo(front.breakdown[2] + back.breakdown[2]),
    3: roundToTwo(front.breakdown[3] + back.breakdown[3])
  };
  const regionsAffected = [...front.regionsAffected, ...back.regionsAffected];

  updateResultsUI(totalTBSA, breakdown, regionsAffected);
  return { total_tbsa: totalTBSA, breakdown, regions: regionsAffected };
}

/* Update result panel */
function updateResultsUI(total, breakdown, regionsAffected){
  totalTBSAEl.textContent = total.toFixed(2) + '%';
  degreeBreakdownEl.innerHTML = '';
  for (const d of [1,2,3]){
    const li = document.createElement('li');
    li.textContent = `${d}º: ${breakdown[d] ? breakdown[d].toFixed(2) : '0.00'}%`;
    degreeBreakdownEl.appendChild(li);
  }
  regionsAffectedEl.innerHTML = '';
  regionsAffected.forEach(r=>{
    const li = document.createElement('li');
    li.textContent = `${r.name}: ${Number(r.percent).toFixed(2)}%`;
    regionsAffectedEl.appendChild(li);
  });
}

/* Draw debug overlay of polygons */
function drawOverlay(){
  ctx.save();
  ctx.lineWidth = 2;
  for (const region of getRegionsForView(view)){
    const pix = polyToPixels(region.poly, view);
    ctx.beginPath();
    ctx.moveTo(pix[0][0], pix[0][1]);
    for (let i=1;i<pix.length;i++) ctx.lineTo(pix[i][0], pix[i][1]);
    ctx.closePath();
    ctx.fillStyle = 'rgba(0,120,200,0.04)';
    ctx.strokeStyle = 'rgba(0,120,200,0.8)';
    ctx.fill();
    ctx.stroke();
    // label
    const cx = pix.reduce((s,p)=>s+p[0],0)/pix.length;
    const cy = pix.reduce((s,p)=>s+p[1],0)/pix.length;
    ctx.fillStyle = 'rgba(0,0,0,0.6)';
    ctx.font = '12px Arial';
    ctx.fillText(region.name, cx+6, cy);
  }
  ctx.restore();
}

/* Draw image + mask + overlay */
function drawAll(){
  ctx.clearRect(0,0,canvasWidth,canvasHeight);
  const img = (view==='front' ? imgFront : imgBack);
  if (img && img.complete && img.naturalWidth){
    const p = computeImagePlacement(img, canvasWidth, canvasHeight);
    ctx.drawImage(img, p.x, p.y, p.w, p.h);
  } else {
    ctx.fillStyle = '#fff';
    ctx.fillRect(0,0,canvasWidth,canvasHeight);
  }
  // draw mask overlay
  ctx.drawImage(maskCanvases[view], 0,0);
  if (debugOverlay) drawOverlay();
}

/* Rebuild mask from strokes */
function rebuildMaskFromStrokes(targetView = view){
  const targetCtx = maskContexts[targetView];
  targetCtx.clearRect(0,0,canvasWidth,canvasHeight);
  for (const s of strokesByView[targetView]) drawStrokeToMask(s, targetView);
  drawAll();
  computeLocalTBSA();
}

/* Draw a stroke to mask */
function drawStrokeToMask(stroke, targetView = view){
  const targetCtx = maskContexts[targetView];
  targetCtx.lineJoin = targetCtx.lineCap = 'round';
  targetCtx.strokeStyle = stroke.color;
  targetCtx.globalCompositeOperation = 'source-over';
  targetCtx.lineWidth = stroke.size;
  targetCtx.beginPath();
  const pts = stroke.points;
  if (!pts || pts.length===0) return;
  targetCtx.moveTo(pts[0].x, pts[0].y);
  for (let i=1;i<pts.length;i++){
    targetCtx.lineTo(pts[i].x, pts[i].y);
  }
  targetCtx.stroke();
}

/* Pointer helpers */
function getPointerPos(evt){
  const rect = mainCanvas.getBoundingClientRect();
  const clientX = (evt.touches ? evt.touches[0].clientX : evt.clientX);
  const clientY = (evt.touches ? evt.touches[0].clientY : evt.clientY);
  const x = (clientX - rect.left) * (mainCanvas.width / rect.width);
  const y = (clientY - rect.top) * (mainCanvas.height / rect.height);
  return { x: Math.round(x), y: Math.round(y) };
}

function startDrawing(x,y){
  isDrawing = true;
  const deg = parseInt(degreeSelect.value);
  const brushSize = parseInt(brushSizeInput.value);
  const color = DEGREE_COLORS[deg].rgba;
  currentStroke = { points: [{x,y}], size: brushSize, degree: deg, color, view };
}

function addPoint(x,y){
  if (!isDrawing || !currentStroke) return;
  currentStroke.points.push({x,y});
  // draw latest segment for instant feedback
  drawStrokeToMask(
    { points: currentStroke.points.slice(-2), size: currentStroke.size, color: currentStroke.color },
    view
  );
  drawAll();
  computeLocalTBSA();
}

function endDrawing(){
  if (!isDrawing) return;
  isDrawing = false;
  if (currentStroke && currentStroke.points.length>0){
    strokesByView[view].push(currentStroke);
    currentStroke = null;
    rebuildMaskFromStrokes(view);
  }
}

/* Event listeners */
mainCanvas.addEventListener('pointerdown', (e)=>{
  mainCanvas.setPointerCapture(e.pointerId);
  const p = getPointerPos(e);
  startDrawing(p.x,p.y);
});
mainCanvas.addEventListener('pointermove', (e)=>{
  if (!isDrawing) return;
  const p = getPointerPos(e);
  addPoint(p.x,p.y);
});
mainCanvas.addEventListener('pointerup', (e)=>{
  if (e.pointerId) mainCanvas.releasePointerCapture(e.pointerId);
  endDrawing();
});
mainCanvas.addEventListener('pointercancel', (e)=> endDrawing());

undoBtn.addEventListener('click', ()=>{
  strokesByView[view].pop();
  rebuildMaskFromStrokes(view);
});
clearBtn.addEventListener('click', ()=>{
  strokesByView[view] = [];
  maskContexts[view].clearRect(0,0,canvasWidth,canvasHeight);
  drawAll();
  computeLocalTBSA();
});
toggleViewBtn.addEventListener('click', ()=>{
  view = (view==='front'? 'back' : 'front');
  toggleViewBtn.textContent = (view==='front' ? 'Show Back' : 'Show Front');
  drawAll();
});
saveBtn.addEventListener('click', async ()=>{
  try {
    if (syncStatusEl) {
      syncStatusEl.textContent = 'Saving assessment...';
      syncStatusEl.style.color = '#0b2e4a';
    }

    // 1) Calculate TBSA locally from separate front/back masks
    const calcJson = computeLocalTBSA();
    const maskBase64Front = maskCanvases.front.toDataURL('image/png');
    const maskBase64Back = maskCanvases.back.toDataURL('image/png');
    const maskBase64 = (view === 'front' ? maskBase64Front : maskBase64Back);

    // 2) Sync TBSA to selected patient (if linked)
    if (activePatientId) {
      const saveToPatientRes = await fetch(`/patients/${encodeURIComponent(activePatientId)}/tbsa-result`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          total_tbsa: calcJson.total_tbsa,
          breakdown: calcJson.breakdown,
          regions: calcJson.regions
        })
      });

      if (!saveToPatientRes.ok) {
        const err = await saveToPatientRes.json();
        throw new Error(err.detail || 'Failed to sync TBSA with patient record');
      }
    }

    // 3) Save burn-mapper assessment snapshot
    const payload = {
      timestamp:new Date().toISOString(),
      mask_base64: maskBase64,
      mask_base64_front: maskBase64Front,
      mask_base64_back: maskBase64Back,
      strokes_by_view: strokesByView,
      strokes: [...strokesByView.front, ...strokesByView.back],
      view,
      total_tbsa: calcJson.total_tbsa,
      breakdown: calcJson.breakdown,
      regions: calcJson.regions,
      patient_id: activePatientId
    };

    const res = await fetch('/tbsa-api/save-assessment', {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify(payload)
    });
    const json = await res.json();

    if (syncStatusEl) {
      syncStatusEl.textContent = 'Assessment saved. Redirecting to Patient Registry...';
      syncStatusEl.style.color = '#15803d';
    }

    const returnWithTbsa = buildReturnUrlWithTbsa(returnUrl, calcJson.total_tbsa);

    setTimeout(() => {
      window.location.href = returnWithTbsa;
    }, 600);

    alert('Saved: ' + (json.id || 'ok') + ` | TBSA: ${calcJson.total_tbsa}%`);
  } catch (e) {
    if (syncStatusEl) {
      syncStatusEl.textContent = `Error: ${e.message || 'Save failed.'}`;
      syncStatusEl.style.color = '#b91c1c';
    }
  }
});
serverCalcBtn.addEventListener('click', async ()=>{
  try {
    if (syncStatusEl) {
      syncStatusEl.textContent = 'Calculating TBSA...';
      syncStatusEl.style.color = '#0b2e4a';
    }

    const json = computeLocalTBSA();

    if (activePatientId) {
      const saveRes = await fetch(`/patients/${encodeURIComponent(activePatientId)}/tbsa-result`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          total_tbsa: json.total_tbsa,
          breakdown: json.breakdown,
          regions: json.regions
        })
      });

      if (!saveRes.ok) {
        const err = await saveRes.json();
        throw new Error(err.detail || 'Failed to update patient TBSA');
      }

      if (syncStatusEl) {
        syncStatusEl.textContent = `Patient TBSA updated successfully (${json.total_tbsa}%).`;
        syncStatusEl.style.color = '#15803d';
      }
    } else if (syncStatusEl) {
      syncStatusEl.textContent = `TBSA calculated (${json.total_tbsa}%). Opened without patient link.`;
      syncStatusEl.style.color = '#92400e';
    }

    alert('Server TBSA: ' + json.total_tbsa + '%');
  } catch (e) {
    if (syncStatusEl) {
      syncStatusEl.textContent = `Error: ${e.message || 'TBSA calculation/update failed.'}`;
      syncStatusEl.style.color = '#b91c1c';
    }
  }
});

/* Initial setup */
function resizeCanvases(w,h){
  canvasWidth = w; canvasHeight = h;
  mainCanvas.width = canvasWidth;
  mainCanvas.height = canvasHeight;
  maskCanvases.front.width = canvasWidth;
  maskCanvases.front.height = canvasHeight;
  maskCanvases.back.width = canvasWidth;
  maskCanvases.back.height = canvasHeight;
}
resizeCanvases(400,900);
drawAll();
computeLocalTBSA();
